/* Suggested markup: <div class="uiwiki-twin-track-action" tabindex="0"><span>Twin Track Action</span></div> */
.uiwiki-twin-track-action {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-twin-track-action > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: twin_track_action 1.8s ease-in-out infinite alternate;
}
.uiwiki-twin-track-action:hover,
.uiwiki-twin-track-action:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes twin_track_action {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-twin-track-action, .uiwiki-twin-track-action > span { animation: none; transition: none; }
}
